export const routes = {
  aboutUs: "About us",
  services: "Services",
  ourWork: "Our work",
  contact: "Contact",
};

export const routesEN = [
  {
    name: "About us",
    path: routes.aboutUs,
  },
  {
    name: "Services",
    path: routes.services,
  },
  {
    name: "Our work",
    path: routes.ourWork,
  },
  {
    name: "Contact",
    path: routes.contact,
  },
];
